<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">tbl[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;FieldName&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] := &lt;newValue&gt;;</span></span>
